    ```java
import java.util.ArrayList;
import java.util.List;

public List<Integer> modifyArray(List<Integer> nums) {
    int n = nums.size();
    for (int i = 1; i < n; ++i) {
        if (gcd(nums.get(i - 1), nums.get(i)) > 1) {
            nums.add(i, 1);
            ++n;
            ++i;
        }
    }
    return nums;
}

private int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}
```

